# sync-engine.js
class SyncEngine {
    constructor(apiUrl = 'http://localhost:5000') {
        this.apiUrl = apiUrl;
        this.syncInterval = 1000;
        this.isConnected = false;
    }
    async sync() {
        try {
            const response = await fetch(`${this.apiUrl}/api/health`);
            const data = await response.json();
            this.isConnected = data.status === 'ok';
            updateStatus(this.isConnected);
            return this.isConnected;
        } catch (error) {
            console.error('Sync error:', error);
            this.isConnected = false;
            updateStatus(false);
            return false;
        }
    }
    start() {
        setInterval(() => this.sync(), this.syncInterval);
        this.sync();
    }
}
const syncEngine = new SyncEngine();
function updateStatus(connected) {
    const statusEl = document.getElementById('status');
    if (connected) {
        statusEl.textContent = '✅ Status: Conectado';
        statusEl.style.background = '#e8f5e9';
        statusEl.style.borderLeftColor = '#4caf50';
    } else {
        statusEl.textContent = '❌ Status: Desconectado';
        statusEl.style.background = '#ffebee';
        statusEl.style.borderLeftColor = '#f44336';
    }
}
window.addEventListener('load', () => {
    syncEngine.start();
});

