        if voice:
            return self.ai_models.recognize_voice(voice)
        return None
    def process_vision(self, vision):
        if vision is not None:
            faces = self.ai_models.detect_faces(vision)
            objects = self.ai_models.detect_objects(vision)
            return {'faces': len(faces), 'objects': objects}
        return None
    def process_screen(self, screen):
        return {'content': screen}

