class MainOrchestrator:
    def __init__(self):
        self.running = False
        self.loop_interval = 1
    def start(self):
        self.running = True
        print('Orquestrador iniciado')
        self.run_loop()
    def stop(self):
        self.running = False
        print('Orquestrador parado')
    def run_loop(self):
        while self.running:
            try:
                response = response_detector.detect()
                if response:
                    command = command_parser.parse(response)
                    if command:
                        result = self.execute_command(command)
                        feedback_sender.send_success(f'Comando executado: {command}')
