import pyautogui
import time

class AutoTyper:
    def __init__(self, interval=0.05):
        self.interval = interval
    def type_text(self, text):
        try:
            pyautogui.typewrite(text, interval=self.interval)
            return True
        except Exception as e:
            print(f'Erro ao digitar: {e}')
            return False
    def type_with_delay(self, text, delay=0.1):
        try:
            for char in text:
                pyautogui.typewrite(char)
                time.sleep(delay)
            return True
        except Exception as e:
            print(f'Erro ao digitar com delay: {e}')
            return False
    def press_key(self, key):
        try:
            pyautogui.press(key)
            return True
        except Exception as e:
            print(f'Erro ao pressionar tecla: {e}')
            return False

auto_typer = AutoTyper()

