import subprocess
import os

class CommandExecutor:
    def __init__(self):
        self.last_output = None
    def execute(self, cmd):
        try:
            result = subprocess.run(
                cmd,
                shell=True,
                capture_output=True,
                text=True,
                timeout=30
            )
            self.last_output = result.stdout
            return result.stdout
        except subprocess.TimeoutExpired:
            return 'Comando expirou'
        except Exception as e:
            return f'Erro ao executar: {e}'
    def execute_powershell(self, script):
        try:
            result = subprocess.run(
                ['powershell', '-Command', script],
                capture_output=True,
                text=True,
                timeout=30
            )
            return result.stdout
        except Exception as e:
            return f'Erro ao executar PowerShell: {e}'
    def get_last_output(self):
        return self.last_output

command_executor = CommandExecutor()

# communication_protocol.py
import json
import hashlib
import time

class CommunicationProtocol:
    def __init__(self, version='1.0'):
        self.version = version
    def encode(self, data):
        message = {
            'version': self.version,
            'timestamp': time.time(),
            'data': data,
            'checksum': self._calculate_checksum(data)
        }
        return json.dumps(message)
    def decode(self, message):
        try:
            parsed = json.loads(message)
            if self._verify_checksum(parsed):
                return parsed['data']
            return None
        except Exception as e:
            print(f'Erro ao decodificar: {e}')
            return None
    def _calculate_checksum(self, data):
        data_str = json.dumps(data, sort_keys=True)
        return hashlib.md5(data_str.encode()).hexdigest()
    def _verify_checksum(self, message):
        expected = self._calculate_checksum(message['data'])
        return expected == message.get('checksum')

protocol = CommunicationProtocol()

